                padding: 4px;
            }

            .action-error-dismiss:hover {
                opacity: 1;
            }

            /* Condition action icons */
            .condition-action-icons {
                align-items: center;
                display: flex;
                gap: 4px;
                margin-left: auto;
            }

            .condition-edit-icon,
            .condition-delete-icon {
