        const accessText = isActive ? 'Access allowed' : 'Access blocked';
        switch (domain) {
            case 'calendar':
                return isActive ? `Event active – ${accessText}` : `No event – ${accessText}`;
            case 'schedule':
                return isActive
                    ? `In schedule – ${accessText}`
                    : `Outside schedule – ${accessText}`;
